#include <stdio.h>

/* == EXEMPLE ================================================
 * Construire une ligne de log avec snprintf
 * snprintf(buf, size, fmt, ...) retourne les chars VOULUS
 * Si retour >= size, la chaine a ete tronquee
 * =========================================================== */
void example_log_line(void) {
    char logbuf[128];
    int level = 3;
    char *module = "network";
    int line = 157;
    int n = snprintf(logbuf, sizeof(logbuf),
                     "[WARN-%d] %s:%d connection timeout", level, module, line);
    if (n >= (int)sizeof(logbuf)) {
        printf("TRONQUE\n");
    } else {
        printf("%s\n", logbuf);
    }
    char tiny[15];
    n = snprintf(tiny, sizeof(tiny), "module=%s line=%d", module, line);
    printf("Tronque: %s\n", n >= (int)sizeof(tiny) ? "oui" : "non");
}
/* Resultat: [WARN-3] network:157 connection timeout / Tronque: oui */

